			Expect(err).NotTo(HaveOccurred())

			// Add a corrupted/invalid audio file
			invalidFile := filepath.Join(tempDir, "corrupted.mp3")
			err = os.WriteFile(invalidFile, []byte("not a real mp3 file"), 0644)
			Expect(err).NotTo(HaveOccurred())

			// Run scan - should not fail on corrupted file
			progress := make(chan uint32, 100)
			_, err = scanner.Scan(ctx, library, true, progress)

			// Scan should complete despite corrupted file
			Expect(err).NotTo(HaveOccurred())

			// Valid files should still be imported
			mediaFileRepo := ds.MediaFile(ctx)
			files, err := mediaFileRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			// Should have imported at least the valid fixture files
			Expect(files).NotTo(BeEmpty())
		})

		It("should skip non-audio files during scan", func() {
			// Create a non-audio file
			txtFile := filepath.Join(tempDir, "readme.txt")
			err := os.WriteFile(txtFile, []byte("not an audio file"), 0644)
			Expect(err).NotTo(HaveOccurred())

			// Add some real audio files
			err = copyTestFixtures(tempDir)
			Expect(err).NotTo(HaveOccurred())

			// Run scan
			progress := make(chan uint32, 100)
			_, err = scanner.Scan(ctx, library, true, progress)
			Expect(err).NotTo(HaveOccurred())

			// Only audio files should be imported
			mediaFileRepo := ds.MediaFile(ctx)
			files, err := mediaFileRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			for _, file := range files {
				// All imported files should be audio files
				Expect(model.IsAudioFile(file.Path)).To(BeTrue())
			}
		})
	})

	Describe("Nested directory structure", func() {
		It("should recursively scan subdirectories", func() {
			// Create nested directory structure
			subdir := filepath.Join(tempDir, "artist", "album")
			err := os.MkdirAll(subdir, 0755)
			Expect(err).NotTo(HaveOccurred())

			// Copy a test file to nested directory
			srcFile := "tests/fixtures/test.mp3"
			destFile := filepath.Join(subdir, "test.mp3")

			sourceContent, err := os.ReadFile(srcFile)
			Expect(err).NotTo(HaveOccurred())
			err = os.WriteFile(destFile, sourceContent, 0644)
			Expect(err).NotTo(HaveOccurred())

			// Run scan
			progress := make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, library, true, progress)
			Expect(err).NotTo(HaveOccurred())

			// Should find the nested file
			Expect(changeCount).To(BeNumerically(">", 0))

			mediaFileRepo := ds.MediaFile(ctx)
			files, err := mediaFileRepo.GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(files).NotTo(BeEmpty())

			// Verify the nested file was found
			nestedFile := findMediaFileByPath(files, destFile)
			Expect(nestedFile).NotTo(BeNil())
		})
	})
})

// Helper functions

// copyTestFixtures copies audio files from tests/fixtures to the target directory
func copyTestFixtures(targetDir string) error {
	sourceDir := "tests/fixtures"

	// Files to copy
	fixturesToCopy := []string{
		"test.mp3",
		"test.flac",
		"test.m4a",
		"test.ogg",
		"test.wav",
	}

	for _, filename := range fixturesToCopy {
		sourcePath := filepath.Join(sourceDir, filename)
		destPath := filepath.Join(targetDir, filename)

		// Check if source exists
		if _, err := os.Stat(sourcePath); err != nil {
			if os.IsNotExist(err) {
				// Skip if fixture doesn't exist
				continue
			}
			return err
		}

		// Read source file
		content, err := os.ReadFile(sourcePath)
		if err != nil {
			return err
		}

		// Write to destination
		err = os.WriteFile(destPath, content, 0644)
		if err != nil {
			return err
		}
	}

	return nil
}

// findMediaFileByName searches for a media file by its filename
func findMediaFileByName(files model.MediaFiles, name string) *model.MediaFile {
	for i, f := range files {
		if filepath.Base(f.Path) == name {
			return &files[i]
		}
	}
	return nil
}

// findMediaFileByPath searches for a media file by its full path
func findMediaFileByPath(files model.MediaFiles, path string) *model.MediaFile {
	for i, f := range files {
		if f.Path == path {
			return &files[i]
		}
	}
	return nil
}
